      audioStreamType: M2tsAudioStreamType.t option
        [@ocaml.doc
          "When set to atsc, uses stream type = 0x81 for AC3 and stream type = 0x87 for EAC3. When set to dvb, uses stream type = 0x06."];
      bitrate: Zz__integerMin0.t option
        [@ocaml.doc
          "The output bitrate of the transport stream in bits per second. Setting to 0 lets the muxer automatically determine the appropriate bitrate."];
      bufferModel: M2tsBufferModel.t option
        [@ocaml.doc
          "Controls the timing accuracy for output network traffic. Leave as MULTIPLEX to ensure accurate network packet timing. Or set to NONE, which might result in lower latency but will result in more variability in output network packet timing. This variability might cause interruptions, jitter, or bursty behavior in your playback or receiving devices."];
      ccDescriptor: M2tsCcDescriptor.t option
        [@ocaml.doc
          "When set to enabled, generates captionServiceDescriptor in PMT."];
      dvbNitSettings: DvbNitSettings.t option
        [@ocaml.doc
          "Inserts DVB Network Information Table (NIT) at the specified table repetition interval."];
      dvbSdtSettings: DvbSdtSettings.t option
        [@ocaml.doc
          "Inserts DVB Service Description Table (SDT) at the specified table repetition interval."];
      dvbSubPids: Zz__string.t option
        [@ocaml.doc
          "Packet Identifier (PID) for input source DVB Subtitle data to this output. Multiple values are accepted, and can be entered in ranges and/or by comma separation. Can be entered as decimal or hexadecimal values. Each PID specified must be in the range of 32 (or 0x20)..8182 (or 0x1ff6)."];
      dvbTdtSettings: DvbTdtSettings.t option
        [@ocaml.doc
          "Inserts DVB Time and Date Table (TDT) at the specified table repetition interval."];
      dvbTeletextPid: Zz__string.t option
        [@ocaml.doc
          "Packet Identifier (PID) for input source DVB Teletext data to this output. Can be entered as a decimal or hexadecimal value. Valid values are 32 (or 0x20)..8182 (or 0x1ff6)."];
      ebif: M2tsEbifControl.t option
        [@ocaml.doc
          "If set to passthrough, passes any EBIF data from the input source to this output."];
      ebpAudioInterval: M2tsAudioInterval.t option
        [@ocaml.doc
          "When videoAndFixedIntervals is selected, audio EBP markers will be added to partitions 3 and 4. The interval between these additional markers will be fixed, and will be slightly shorter than the video EBP marker interval. Only available when EBP Cablelabs segmentation markers are selected. Partitions 1 and 2 will always follow the video interval."];
      ebpLookaheadMs: Zz__integerMin0Max10000.t option
        [@ocaml.doc
          "When set, enforces that Encoder Boundary Points do not come within the specified time interval of each other by looking ahead at input video. If another EBP is going to come in within the specified time interval, the current EBP is not emitted, and the segment is \"stretched\" to the next marker. The lookahead value does not add latency to the system. The Live Event must be configured elsewhere to create sufficient latency to make the lookahead accurate."];
      ebpPlacement: M2tsEbpPlacement.t option
        [@ocaml.doc
