        [@ocaml.doc
          "If set to passthrough for an audio-only MS Smooth output, the fragment absolute time will be set to the current timecode. This option does not write timecodes to the audio elementary stream."];
      certificateMode: SmoothGroupCertificateMode.t option
        [@ocaml.doc
          "If set to verifyAuthenticity, verify the https certificate chain to a trusted Certificate Authority (CA). This will cause https outputs to self-signed certificates to fail."];
      connectionRetryInterval: Zz__integerMin0.t option
        [@ocaml.doc
          "Number of seconds to wait before retrying connection to the IIS server if the connection is lost. Content will be cached during this time and the cache will be be delivered to the IIS server once the connection is re-established."];
      destination: OutputLocationRef.t
        [@ocaml.doc
          "Smooth Streaming publish point on an IIS server. Elemental Live acts as a \"Push\" encoder to IIS."];
      eventId: Zz__string.t option
        [@ocaml.doc
          "MS Smooth event ID to be sent to the IIS server. Should only be specified if eventIdMode is set to useConfigured."];
      eventIdMode: SmoothGroupEventIdMode.t option
        [@ocaml.doc
          "Specifies whether or not to send an event ID to the IIS server. If no event ID is sent and the same Live Event is used without changing the publishing point, clients might see cached video from the previous run. Options: - \"useConfigured\" - use the value provided in eventId - \"useTimestamp\" - generate and send an event ID based on the current timestamp - \"noEventId\" - do not send an event ID to the IIS server."];
      eventStopBehavior: SmoothGroupEventStopBehavior.t option
        [@ocaml.doc
          "When set to sendEos, send EOS signal to IIS server when stopping the event"];
      filecacheDuration: Zz__integerMin0.t option
        [@ocaml.doc "Size in seconds of file cache for streaming outputs."];
      fragmentLength: Zz__integerMin1.t option
        [@ocaml.doc
          "Length of mp4 fragments to generate (in seconds). Fragment length must be compatible with GOP size and framerate."];
      inputLossAction: InputLossActionForMsSmoothOut.t option
        [@ocaml.doc
          "Parameter that control output group behavior on input loss."];
      numRetries: Zz__integerMin0.t option
        [@ocaml.doc "Number of retry attempts."];
      restartDelay: Zz__integerMin0.t option
