        ("secretArn", (Option.map x.secretArn ~f:Zz__string.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let secretArn =
        (Option.map ~f:Zz__string.of_xml) (Xml.child xml_arg0 "secretArn") in
      let encryptionType =
        (Option.map ~f:RouterEncryptionType.of_xml)
          (Xml.child xml_arg0 "encryptionType") in
      let destinations =
        (Option.map ~f:Zz__listOfRouterDestination.of_xml)
